#include <stdio.h>

int main() {
  int number = 13; // Binary: 1101
  int bit_position = 2;

  // Bitin yoxlanması (bit_position-da 1 varmı?)
  int is_set = (number & (1 << bit_position)) ? 1 : 0;
  printf("Bit %d: %d\n", bit_position, is_set);

  // Bitin qurulması (bit_position-da 1 qoymaq)
  number = number | (1 << bit_position);
  printf("Bit qurulduktan sonra: %d\n", number); // 1101 | 0100 = 1101 (artıq 1)

  // Bitin silinməsi (bit_position-da 0 qoymaq)
  number = number & ~(1 << bit_position);
  printf("Bit silindikdən sonra: %d\n", number); // 1101 & 1011 = 1001 = 9
  return 0;
}
// Output:
// Bit 2: 1
// Bit qurulduktan sonra: 13
// Bit silindikdən sonra: 9

#include <stdio.h>

#define READ 1   // 0001
#define WRITE 2  // 0010
#define EXECUTE 4 // 0100

int main() {
  int permissions = 0; // Başlanğıc icazələr: 0000

  // İcazələri qurmaq
  permissions |= READ | WRITE; // 0000 | 0011 = 0011
  printf("Icazeler: %d\n", permissions);

  // READ icazəsinin yoxlanması
  if (permissions & READ) {
    printf("Oxuma icazesi var\n");
  }

  // EXECUTE icazəsinin silinməsi
  permissions &= ~EXECUTE; // 0011 & 1011 = 0011
  printf("EXECUTE silindikden sonra: %d\n", permissions);
  return 0;
}
// Output:
// Icazeler: 3
// Oxuma icazesi var
// EXECUTE silindikden sonra: 3

