#include <stdio.h>

int main() {
  int number = 13; // Binary: 1101
  int bit_position = 2;

  // Check if bit is set
  int is_set = (number & (1 << bit_position)) ? 1 : 0;
  printf("Bit %d: %d\n", bit_position, is_set);

  // Set a bit
  number = number | (1 << bit_position);
  printf("After setting bit: %d\n", number); // 1101 | 0100 = 1101 (already set)

  // Clear a bit
  number = number & ~(1 << bit_position);
  printf("After clearing bit: %d\n", number); // 1101 & 1011 = 1001 = 9
  return 0;
}
// Output:
// Bit 2: 1
// After setting bit: 13
// After clearing bit: 9

#include <stdio.h>

#define READ 1   // 0001
#define WRITE 2  // 0010
#define EXECUTE 4 // 0100

int main() {
  int permissions = 0; // Initial permissions: 0000

  // Set permissions
  permissions |= READ | WRITE; // 0000 | 0011 = 0011
  printf("Permissions: %d\n", permissions);

  // Check READ permission
  if (permissions & READ) {
    printf("Read permission is set\n");
  }

  // Clear EXECUTE permission
  permissions &= ~EXECUTE; // 0011 & 1011 = 0011
  printf("After clearing EXECUTE: %d\n", permissions);
  return 0;
}
// Output:
// Permissions: 3
// Read permission is set
// After clearing EXECUTE: 3

