#include <stdio.h>

int main() {
  int number = 13; // Binary: 1101
  int bit_position = 2;

  // Проверка бита
  int is_set = (number & (1 << bit_position)) ? 1 : 0;
  printf("Бит %d: %d\n", bit_position, is_set);

  // Установка бита
  number = number | (1 << bit_position);
  printf("После установки бита: %d\n", number); // 1101 | 0100 = 1101 (уже установлен)

  // Сброс бита
  number = number & ~(1 << bit_position);
  printf("После сброса бита: %d\n", number); // 1101 & 1011 = 1001 = 9
  return 0;
}
// Output:
// Бит 2: 1
// После установки бита: 13
// После сброса бита: 9

#include <stdio.h>

#define READ 1   // 0001
#define WRITE 2  // 0010
#define EXECUTE 4 // 0100

int main() {
  int permissions = 0; // Начальные разрешения: 0000

  // Установка разрешений
  permissions |= READ | WRITE; // 0000 | 0011 = 0011
  printf("Разрешения: %d\n", permissions);

  // Проверка разрешения READ
  if (permissions & READ) {
    printf("Разрешение на чтение установлено\n");
  }

  // Сброс разрешения EXECUTE
  permissions &= ~EXECUTE; // 0011 & 1011 = 0011
  printf("После сброса EXECUTE: %d\n", permissions);
  return 0;
}
// Output:
// Разрешения: 3
// Разрешение на чтение установлено
// После сброса EXECUTE: 3

